import {
  BookOpen,
  ClipboardList,
  Clock,
  CheckCircle2,
  GraduationCap,
  LogOut,
  ChevronRight,
  CalendarDays,
  BarChart3,
  MessageSquare,
  Settings,
  User,
  Plus,
  Bell,
  TrendingUp,
  BookMarked,
  AlertCircle,
  Hash,
} from "lucide-react";
import { useAuth } from "@/utils/AuthContext";
import { useRouter } from "next/navigation";
import { useStudentDashboardStats } from "@/hooks/queries/useStudentDashboardStats";
import { useQuery } from "@tanstack/react-query";
