/* ══════════════════════════════════════════════════════════
   Sidebar
   ══════════════════════════════════════════════════════════ */

type NavId = "courses" | "assignments" | "grades" | "calendar" | "reports" | "account" | "settings" | "discussion";
interface NavItem { id: NavId; icon: React.ElementType; label: string; }

const NAV_ITEMS: NavItem[] = [
  { id: "courses",     icon: BookOpen,      label: "Courses"     },
  { id: "assignments", icon: ClipboardList, label: "Assignments" },
  { id: "grades",      icon: TrendingUp,    label: "Grades"      },
  { id: "calendar",    icon: CalendarDays,  label: "Calendar"    },
  { id: "reports",     icon: BarChart3,     label: "Reports"     },
  { id: "discussion",  icon: MessageSquare, label: "Discussion"  },
  { id: "account",     icon: User,          label: "Account"     },
  { id: "settings",    icon: Settings,      label: "Settings"    },
];

function StudentSidebar({
  active, onNav, onLogout, userName, userEmail,
}: {
  active: NavId; onNav: (id: NavId) => void; onLogout: () => void;
  userName: string; userEmail: string;
}) {
  return (
    <aside className="flex flex-col h-screen sticky top-0"
      style={{ width: "240px", minWidth: "240px", backgroundColor: "#6B0000", borderRight: "1px solid rgba(255,255,255,0.08)" }}>
      {/* Logo */}
      <div className="flex items-center gap-3 px-5 py-5" style={{ borderBottom: "1px solid rgba(255,255,255,0.10)" }}>
        <div className="w-9 h-9 rounded-lg flex items-center justify-center flex-shrink-0"
          style={{ backgroundColor: "rgba(255,255,255,0.15)" }}>
          <GraduationCap className="w-5 h-5 text-white" />
        </div>
        <div>
          <p className="text-white font-bold text-sm leading-tight">AutoGrade</p>
          <p className="text-xs leading-tight" style={{ color: "rgba(255,255,255,0.55)" }}>ULM Student Portal</p>
        </div>
      </div>
      {/* Nav items */}
      <nav className="flex-1 py-4 overflow-y-auto">
        {NAV_ITEMS.map((item) => {
          const Icon = item.icon;
          const isActive = active === item.id;
          return (
            <button key={item.id} onClick={() => onNav(item.id)}
              className="w-full flex items-center gap-3 px-5 py-3 transition-all relative"
              style={{ background: isActive ? "rgba(255,255,255,0.15)" : "transparent", color: isActive ? "white" : "rgba(255,255,255,0.65)" }}>
              {isActive && <div className="absolute left-0 top-0 bottom-0 w-1 rounded-r" style={{ backgroundColor: "#C9A84C" }} />}
              <Icon style={{ width: "18px", height: "18px", flexShrink: 0 }} />
              <span style={{ fontSize: "13.5px", fontWeight: isActive ? 600 : 400 }}>{item.label}</span>
            </button>
          );
        })}
      </nav>
      {/* User footer */}
      <div style={{ borderTop: "1px solid rgba(255,255,255,0.10)", padding: "16px 20px" }}>
        <div className="flex items-center gap-3 mb-3">
          <div className="w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 text-sm font-bold"
            style={{ backgroundColor: "#C9A84C", color: "#6B0000" }}>
            {userName.charAt(0).toUpperCase()}
          </div>
          <div className="flex-1 min-w-0">
            <p className="text-white font-semibold text-xs truncate">{userName}</p>
            <p className="text-xs truncate" style={{ color: "rgba(255,255,255,0.5)" }}>{userEmail}</p>
          </div>
        </div>
        <button onClick={onLogout}
          className="w-full flex items-center gap-2 py-2 px-3 rounded-lg text-xs"
          style={{ background: "rgba(255,255,255,0.08)", color: "rgba(255,255,255,0.75)" }}>
          <LogOut style={{ width: "14px", height: "14px" }} /> Sign Out
        </button>
      </div>
    </aside>
  );
}

/* ══════════════════════════════════════════════════════════
   Stat Card
   ══════════════════════════════════════════════════════════ */
function StatCard({ icon, label, value, accent, bg }: {
  icon: React.ReactNode; label: string; value: string | number; accent: string; bg: string;
}) {
  return (
    <div className="rounded-xl flex items-center gap-4 p-5"
      style={{ backgroundColor: "white", border: "1px solid var(--color-border)", boxShadow: "0 1px 4px rgba(107,0,0,0.06)" }}>
      <div className="w-11 h-11 rounded-xl flex items-center justify-center flex-shrink-0"
        style={{ backgroundColor: bg, color: accent }}>{icon}</div>
      <div>
        <p className="text-2xl font-bold leading-tight" style={{ color: "var(--color-text-dark)" }}>{value}</p>
        <p className="text-xs mt-0.5" style={{ color: "var(--color-text-mid)" }}>{label}</p>
      </div>
    </div>
  );
}

/* ══════════════════════════════════════════════════════════
   Course Card
   ══════════════════════════════════════════════════════════ */
const CARD_COLORS = ["#6B0000","#1E40AF","#15803D","#B45309","#7C3AED","#0F766E"];

function CourseCard({ course, idx, onClick }: { course: any; idx: number; onClick: () => void }) {
  const color = CARD_COLORS[idx % CARD_COLORS.length];
  const initials = (course.name || "C").split(" ").slice(0, 2).map((w: string) => w[0]).join("").toUpperCase();
  return (
    <button onClick={onClick}
      className="group text-left rounded-xl overflow-hidden transition-all hover:-translate-y-0.5 hover:shadow-lg"
      style={{ backgroundColor: "white", border: "1px solid var(--color-border)", boxShadow: "0 1px 4px rgba(107,0,0,0.06)" }}>
      <div className="h-20 flex items-end px-5 pb-3" style={{ backgroundColor: color }}>
        <div className="w-10 h-10 rounded-lg flex items-center justify-center text-sm font-bold"
          style={{ backgroundColor: "rgba(255,255,255,0.2)", color: "white" }}>{initials}</div>
      </div>
      <div className="p-4">
        <p className="font-semibold text-sm leading-snug mb-1" style={{ color: "var(--color-text-dark)" }}>{course.name}</p>
        {course.code && (
          <p className="text-xs flex items-center gap-1" style={{ color: "var(--color-text-light)" }}>
            <Hash style={{ width: "12px", height: "12px" }} />{course.code}
          </p>
        )}
        <div className="mt-3 flex items-center justify-between"
          style={{ borderTop: "1px solid var(--color-border)", paddingTop: "10px" }}>
          <span className="text-xs font-medium" style={{ color }}>Go to Course</span>
          <ChevronRight className="w-4 h-4 opacity-0 group-hover:opacity-100 transition-opacity" style={{ color }} />
        </div>
      </div>
    </button>
  );
}

function StatCard({
  icon,
  label,
  value,
  color,
}: {
  icon: React.ReactNode;
  label: string;
  value: string | number;
  color: string;
}) {
  return (
    <div className="bg-white rounded-xl border border-[var(--color-border)] p-5 flex items-center gap-4">
      <div
        className="w-12 h-12 rounded-lg flex items-center justify-center flex-shrink-0"
        style={{ backgroundColor: color, color: "white" }}
      >
        {icon}
      </div>
      <div>
        <p className="text-2xl font-bold" style={{ color: "var(--color-text-dark)" }}>
          {value}
        </p>
        <p className="text-sm" style={{ color: "var(--color-text-mid)" }}>
          {label}
        </p>
      </div>
    </div>
  );
}

function StudentDashboard() {
  const { user, logout } = useAuth();
  const router = useRouter();
  const { data: stats, isLoading } = useStudentDashboardStats();

  const handleLogout = () => {
    logout();
    router.push("/login");
  };

  const firstName = (user as any)?.firstName ?? user?.email?.split("@")[0] ?? "Student";

  return (
    <PageLayout>
      <main className="max-w-5xl mx-auto px-4 py-8">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h1 className="text-2xl font-bold" style={{ color: "var(--color-text-dark)" }}>
              Welcome back, {firstName}!
            </h1>
            <p className="mt-1 text-sm" style={{ color: "var(--color-text-mid)" }}>
              Here's an overview of your courses and assignments.
            </p>
          </div>
          <Button variant="outline" onClick={handleLogout} className="gap-2">
            <LogOut className="w-4 h-4" />
            Sign Out
          </Button>
        </div>
        {/* Stat Cards */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
          <StatCard icon={<BookOpen className="w-6 h-6" />} label="Enrolled Courses" value={stats?.courses?.length ?? 0} color="#6B0000" />
          <StatCard icon={<ClipboardList className="w-6 h-6" />} label="Total Assignments" value={stats?.total_assignments ?? 0} color="#2563EB" />
          <StatCard icon={<Clock className="w-6 h-6" />} label="Pending" value={stats?.pending_assignments ?? 0} color="#D97706" />
          <StatCard icon={<CheckCircle2 className="w-6 h-6" />} label="Completed" value={stats?.completed_assignments ?? 0} color="#16A34A" />
        </div>
        {/* Courses List */}
        <div>
          <h2 className="text-lg font-semibold mb-4" style={{ color: "var(--color-text-dark)" }}>
            Your Courses
          </h2>
          {isLoading ? (
            <div className="text-center py-16 text-sm" style={{ color: "var(--color-text-mid)" }}>
              Loading courses…
            </div>
          ) : stats?.courses?.length === 0 ? (
            <div className="text-center py-16 border rounded-xl bg-white" style={{ borderColor: "var(--color-border)" }}>
              <GraduationCap className="w-12 h-12 mx-auto mb-3" style={{ color: "var(--color-text-light)" }} />
              <p className="font-medium" style={{ color: "var(--color-text-dark)" }}>
                No courses yet
              </p>
              <p className="text-sm mt-1" style={{ color: "var(--color-text-mid)" }}>
                You haven't been enrolled in any courses.
              </p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {stats && Array.isArray(stats.courses)
                ? stats.courses.map((course: any) => (
                    <button
                      key={course.id}
                      onClick={() => router.push(`/student/courses/${course.id}`)}
                      className="text-left bg-white rounded-xl border border-[var(--color-border)] p-5 hover:border-[var(--color-primary)] transition-colors group"
                    >
                      <div className="flex items-start justify-between">
                        <div className="flex-1 min-w-0">
                          <p className="font-semibold truncate" style={{ color: "var(--color-text-dark)" }}>
                            {course.name}
                          </p>
                          <p className="text-sm mt-0.5" style={{ color: "var(--color-text-mid)" }}>
                            {course.code}
                          </p>
                        </div>
                        <ChevronRight className="w-5 h-5 flex-shrink-0 mt-0.5 opacity-0 group-hover:opacity-100 transition-opacity" style={{ color: "var(--color-primary)" }} />
                      </div>
                    </button>
                  ))
                : null}
            </div>
          )}
        </div>
      </main>
    </PageLayout>
  );
}

export default StudentDashboard;